<template>
  <div class="min-h-screen bg text-white flex flex-col items-center justify-between px-6" :style="bgStyle">
    <!-- CENTER CONTENT -->
    <div class="flex flex-col items-center mt-20 space-y-4">

      <!-- LOGO -->
      <div class="w-20 h-20 rounded-full flex items-center justify-center" style="padding:10px;">
<!-- Light -->
<img src="@/assets/navio-symbol-light.svg" class="block dark:hidden" style/>

<!-- Dark -->
<img src="@/assets/navio-symbol-dark.svg" class="hidden dark:block" />

  </div>


  <!-- WALLET NAME -->
  <div class="text-sm font-medium text-gray-500 dark:text-gray-400 tracking-wide">{{ walletName }}</div>

  <!-- BALANCE -->
  <div class="text-5xl font-bold tracking-tight text-gray-900 dark:text-white">
    {{ balance }} <span class="text-2xl font-medium text-gray-500 dark:text-gray-400">NAV</span>
  </div>

  <!-- FIAT + 24h -->
  <div class="min-h-[1.5rem] flex items-center gap-2">
    <span v-if="fiatValue != null" class="text-base text-gray-600 dark:text-gray-300">
      ≈ {{ fiatValue }}
    </span>
    <span v-else-if="navPrice.loading" class="text-sm text-gray-400 dark:text-gray-500">···</span>
    <span
      v-if="navPrice.change24h != null && fiatValue != null"
      class="text-xs font-medium px-1.5 py-0.5 rounded-full"
      :class="navPrice.change24h >= 0
        ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400'
        : 'bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400'"
    >
      {{ navPrice.change24h > 0 ? '+' : '' }}{{ navPrice.change24h.toFixed(2) }}%
    </span>
  </div>

  <!-- BLOCK NUMBER -->
  <div
    v-if="settings.showBlockNumber"
    class="text-xs text-gray-400 dark:text-gray-500 font-mono"
  >
    <span v-if="percent < 100">{{ walletHeight.toLocaleString() }} / {{ chainTip.toLocaleString() }}</span>
    <span v-else>Block #{{ walletHeight.toLocaleString() }}</span>
  </div>

  <!-- SYNC PROGRESS -->
  <CircularProgress
    v-if="percent < 100"
    :value="percent"
    :label="$t('wallet.synced')"
    :size="200"
    :stroke-width="3"
  />
</div>
</div>
</template>
<script setup>
  import { onMounted, onUnmounted, computed } from "vue";
  import { settings } from "@/stores/settings";
  import { wallpapers } from "@/assets/wallpapers";
  import { percent, balance, walletName, walletHeight, chainTip } from "@/stores/navio";
  import { navPrice, getPriceIn, startPricePolling, stopPricePolling } from "@/stores/navPrice";
  import CircularProgress from '@/components/CircularProgress.vue'

  const isDark = computed(() => {
    if (settings.theme === 'dark') return true
    if (settings.theme === 'light') return false
    return window.matchMedia('(prefers-color-scheme: dark)').matches
  })

  const bgStyle = computed(() => {
    const wp = wallpapers.find(w => w.id === settings.wallpaper) ?? wallpapers[0]
    if (!wp.dark && !wp.light) return {}
    return { backgroundImage: isDark.value ? wp.dark : wp.light, backgroundSize: 'cover', backgroundPosition: 'center', backgroundRepeat: 'no-repeat' }
  })

  const fiatValue = computed(() => {
    const nav = Number(balance.value)
    if (!nav || isNaN(nav)) return null
    const currency = settings.currency ?? 'USD'
    const price    = getPriceIn(currency)
    if (price == null) return null
    return (nav * price).toLocaleString(undefined, {
      style: 'currency',
      currency,
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    })
  })

  onMounted(() => startPricePolling())
  onUnmounted(() => stopPricePolling())
</script>
